SELECT poll_id, total_votes
FROM polls
ORDER BY total_votes DESC;

SELECT total_votes
FROM polls
WHERE poll_id = 0;

SELECT SUM(clicks) AS total_votes
FROM poll_interactions
WHERE poll_id = 1;

SELECT poll_id, total_votes
FROM polls
ORDER BY total_votes DESC;

SELECT total_votes
FROM polls
ORDER BY total_votes DESC;

SELECT DISTINCT topic
FROM polls
ORDER BY topic;
